16.3 Mock Service Worker (MSW) Strategy
All client-side data fetching goes through the services/ layer
(Chapter 21). MSW intercepts these requests in tests by
registering handlers that mirror the real API contracts. The
handlers live in tests/mocks/handlers.ts and are organised by
service: products.ts, cart.ts, checkout.ts, search.ts. A single setup
file (tests/setup/msw-server.ts) starts the MSW server in
'beforeAll', resets handlers in 'afterEach', and closes in 'afterAll'.
This pattern means component tests never hit a real network and
never depend on the future Supabase backend being available.
// tests/mocks/handlers/products.ts
import { http, HttpResponse } from "msw";
import { mockProducts } from "./data/products";
export const productHandlers = [
http.get("/api/products/:slug", ({ params }) => {

const product = mockProducts.find((p) => p.slug ===
params.slug);
if (!product) return HttpResponse.json({ error: "Not found" },
{ status: 404 });
return HttpResponse.json(product);
}),
http.get("/api/products", ({ request }) => {
const url = new URL(request.url);
const category = url.searchParams.get("category");
const filtered = category
? mockProducts.filter((p) => p.category === category)
: mockProducts;
return HttpResponse.json({ items: filtered, total:
filtered.length });
}),
];
