25.1 Cookie Consent Strategy
On the first visit, a bottom-of-screen cookie banner appears with
the message 'We use cookies to improve your experience and
understand what works. Choose your preferences.' and three
buttons: 'Accept all' (primary gold), 'Essential only' (secondary
outline), and 'Manage preferences' (text link). The banner is non-
blocking — the user can scroll and interact with the site without
dismissing it — and it does not use a dark pattern (no 'Accept all'
is larger or more prominent than 'Essential only'). The choice is
stored in localStorage under the 'aura-consent' key for 12 months.
The 'Manage preferences' view shows three categories: Essential
(always on, includes the cart and auth tokens — these are not
optional), Analytics (Vercel Analytics and the future PostHog
instance — opt-in), and Marketing (the future Meta Pixel and
Google Ads tag — opt-in, off by default). The user can toggle each
independently and save. The consent state is re-checked on every
page load; if the user has not consented to Marketing, the Meta
Pixel script is never injected. This is enforced at the layout level,
not in component code.
// lib/consent.ts — consent state and gating
export type ConsentCategory = "essential" | "analytics" |
"marketing";
export type ConsentState = Record<ConsentCategory,
boolean>;
const STORAGE_KEY = "aura-consent";
const EXPIRY_DAYS = 365;
export function getConsent(): ConsentState | null {
if (typeof window === "undefined") return null;
const raw = localStorage.getItem(STORAGE_KEY);
if (!raw) return null;
try {
const parsed = JSON.parse(raw);
if (Date.now() - parsed.timestamp > EXPIRY_DAYS * 86400000)
return null;
return parsed.state as ConsentState;
} catch {

return null;
}
}
export function hasConsent(category: ConsentCategory):
boolean {
const state = getConsent();
if (!state) return category === "essential";
return state[category] ?? false;
}
// app/layout.tsx — gate marketing scripts on consent
export default async function RootLayout({ children }) {
const consent = getConsent();
return (
<html>
<head>
{consent?.marketing && <Script src="https://
connect.facebook.net/en_US/fbevents.js" />}
</head>
<body>{children}</body>
</html>
);
}
